sql:
SELECT artist_id AS id, artist_name AS name FROM artists
UNION ALL
SELECT user_id AS id, username AS name FROM users;

SELECT g.genre_name, gh.genre_level
FROM genres g
JOIN genres_hierarchy gh ON g.genre_id = gh.genre_id;

SELECT COUNT(ss.similar_song_id) AS similar_songs_count
FROM song_similarities ss
WHERE ss.song_id = 1;

SELECT *
FROM song_similarities
WHERE song_id = 0;

SELECT cluster_id, COUNT(song_id) AS num_songs
FROM song_clusters
GROUP BY cluster_id;

SELECT a.artist_name, ap.profile_name, ap.profile_description
FROM artists a
JOIN artist_profiles ap ON a.artist_id = ap.artist_id;
